**Test 1: `subscribeToRelay flush serialization`**
```typescript
it('flushes relay events in order under backpressure', async () => {
  // Setup: mock res.write() to return false (backpressure) then emit drain
  const res = createMockResponse();
  let drainCallback: (() => void) | null = null;
  res.write = vi.fn().mockImplementation(() => {
    // First call returns false (backpressure), subsequent return true
    if (res.write.mock.calls.length === 1) {
      return false; // Trigger drain wait
    }
    return true;
  });
  res.once = vi.fn().mockImplementation((event, cb) => {
    if (event === 'drain') drainCallback = cb;
  });

  // Publish 3 relay events rapidly
  // Verify all 3 are flushed in order after drain
  // Verify write was called 3 times total
});
```

