it('drains buffered messages when subscriber registers', async () => {
  const registry = new SubscriptionRegistry(testDataDir);
  const envelope1 = createMockEnvelope({ subject: 'relay.human.console.abc' });
  const envelope2 = createMockEnvelope({ subject: 'relay.human.console.abc' });

  registry.bufferForPendingSubscriber('relay.human.console.abc', envelope1);
  registry.bufferForPendingSubscriber('relay.human.console.abc', envelope2);

  const received: RelayEnvelope[] = [];
  registry.subscribe('relay.human.console.abc', async (env) => { received.push(env); });

